"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import { useEffect, useState } from "react"
import { signOut, useSession } from "next-auth/react"
import { AnimatePresence, motion } from "framer-motion"
import {
  BookOpen,
  Calendar,
  CreditCard,
  Dog,
  FileText,
  GraduationCap,
  LayoutDashboard,
  Menu,
  MessageSquare,
  Shield,
  Sparkles,
  UserCircle2,
  Users,
  X,
  type LucideIcon,
} from "lucide-react"

import { getAccountPlanLabel } from "@/lib/platform"
import { isAdminRole, isProfessionalRole, isRootRole, isStaffRole, isTrainerRole } from "@/lib/role"

type NavLink = {
  href: string
  label: string
  icon: LucideIcon
}

const baseLinks: NavLink[] = [
  { href: "/dashboard", label: "Dashboard", icon: LayoutDashboard },
  { href: "/courses", label: "Cursos", icon: GraduationCap },
  { href: "/racas", label: "Racas", icon: Dog },
  { href: "/conteudos", label: "Conteudos", icon: BookOpen },
  { href: "/dogs", label: "Caes", icon: Dog },
  { href: "/dogs/new", label: "Novo cao", icon: Sparkles },
  { href: "/training", label: "Treinos", icon: Sparkles },
  { href: "/calendar", label: "Calendario", icon: Calendar },
  { href: "/blog", label: "Blog", icon: FileText },
  { href: "/forum", label: "Forum", icon: MessageSquare },
  { href: "/billing", label: "Assinatura", icon: CreditCard },
  { href: "/profile", label: "Perfil", icon: UserCircle2 },
]

const rootLinks: NavLink[] = [
  { href: "/dashboard", label: "Root console", icon: Shield },
  { href: "/admin/users", label: "Usuarios", icon: Users },
  { href: "/admin/clients", label: "Clientes", icon: Users },
  { href: "/admin/dogs", label: "Caes", icon: Dog },
  { href: "/admin/trainings", label: "Treinos", icon: Sparkles },
  { href: "/admin/schedule", label: "Agenda", icon: Calendar },
  { href: "/admin/finance", label: "Financeiro", icon: CreditCard },
  { href: "/admin/security", label: "Seguranca", icon: Shield },
  { href: "/admin/companies", label: "Empresas", icon: Users },
]

const guestLinks: NavLink[] = [
  { href: "/", label: "Inicio", icon: LayoutDashboard },
  { href: "/racas", label: "Racas", icon: Dog },
  { href: "/courses", label: "Cursos", icon: GraduationCap },
  { href: "/blog", label: "Blog", icon: FileText },
  { href: "/servicos", label: "Servicos", icon: Sparkles },
  { href: "/#planos", label: "Planos", icon: CreditCard },
]

export default function Navbar() {
  const pathname = usePathname()
  const { data } = useSession()
  const [open, setOpen] = useState(false)

  const isAdmin = isAdminRole(data?.user?.role)
  const isRoot = isRootRole(data?.user?.role)
  const isStaff = isStaffRole(data?.user?.role)
  const isTrainer = isTrainerRole(data?.user?.role)
  const isProfessional = isProfessionalRole(data?.user?.role)
  const needsEmailVerification = !!data?.user && !data.user.emailVerifiedAt
  const adminLabel = isRoot ? "Root" : "Admin"
  const baseNoDashboard = baseLinks.filter((link) => link.href !== "/dashboard")
  const communityLinks: NavLink[] = isStaff
    ? [
        {
          href: "/forum/channels/new",
          label: isTrainer ? "Meu canal" : isProfessional ? "Meu espaco" : "Novo canal",
          icon: MessageSquare,
        },
        { href: "/blog/new", label: "Novo post", icon: FileText },
      ]
    : data?.user
      ? [{ href: "/blog/new", label: "Publicar no blog", icon: FileText }]
      : []

  const links = isRoot
    ? [...rootLinks, ...communityLinks, ...baseNoDashboard]
    : isAdmin
      ? [...baseLinks, ...communityLinks, { href: "/admin", label: adminLabel, icon: Shield }]
      : [...baseLinks, ...communityLinks]

  const resolvedLinks = needsEmailVerification
    ? [{ href: "/verify", label: "Confirmar email", icon: Shield }, ...links]
    : links

  useEffect(() => {
    setOpen(false)
  }, [pathname])

  return (
    <nav className="app-nav sticky top-0 z-50 border-b border-white/10 bg-slate-950/80 px-4 py-4 text-white backdrop-blur-xl sm:px-6">
      <div className="mx-auto flex max-w-7xl items-center justify-between gap-3">
        <Link href={data?.user ? "/dashboard" : "/"} className="group flex min-h-[44px] items-center gap-3 rounded-2xl pr-3 transition-all duration-200">
          <div className="flex h-11 w-11 items-center justify-center rounded-2xl bg-[linear-gradient(135deg,rgba(6,182,212,0.28),rgba(16,185,129,0.35))] shadow-lg shadow-cyan-500/15 transition-all duration-200 group-hover:-translate-y-0.5 group-hover:shadow-cyan-500/25">
            <Dog className="h-5 w-5 text-cyan-100" aria-hidden="true" />
          </div>
          <div>
            <p className="text-sm font-semibold tracking-[0.08em] text-white">K9 Training</p>
            <p className="text-xs text-slate-300">Experiencia mais clara, viva e util para o tutor</p>
          </div>
        </Link>

        <div className="hidden items-center gap-2 lg:flex">
          {data?.user ? (
            <>
              <div className="hidden rounded-2xl border border-white/10 bg-white/5 px-4 py-2 text-xs text-slate-200 xl:block">
                <span className="font-medium text-white">{data.user?.name || data.user?.email}</span>
                <span className="mx-2 text-slate-500">|</span>
                <span>{getAccountPlanLabel(data.user?.plan)}</span>
                {needsEmailVerification ? <span className="ml-2 text-amber-300">Email pendente</span> : null}
              </div>
              <button
                type="button"
                onClick={() => signOut({ callbackUrl: "/login" })}
                className="interactive-button min-h-[44px] rounded-2xl border border-white/15 px-4 py-2 text-sm text-slate-100 transition-all duration-200 hover:bg-white/10"
              >
                Sair
              </button>
            </>
          ) : (
            <div className="flex items-center gap-2">
              <Link
                href="/login"
                className="interactive-button flex min-h-[44px] items-center rounded-2xl border border-white/15 px-4 py-2 text-sm text-slate-100 transition-all duration-200 hover:bg-white/10"
              >
                Entrar
              </Link>
              <Link
                href="/register"
                className="interactive-button flex min-h-[44px] items-center rounded-2xl bg-[linear-gradient(135deg,#06b6d4,#10b981)] px-4 py-2 text-sm font-semibold text-white shadow-lg shadow-cyan-500/25 transition-all duration-200 hover:-translate-y-0.5"
              >
                Criar conta
              </Link>
            </div>
          )}
        </div>

        <button
          type="button"
          onClick={() => setOpen((prev) => !prev)}
          className="interactive-button flex min-h-[44px] min-w-[44px] items-center justify-center rounded-2xl border border-white/15 bg-white/5 p-3 text-slate-100 transition-all duration-200 hover:bg-white/10 lg:hidden"
          aria-expanded={open}
          aria-controls="app-menu"
          aria-label={open ? "Fechar navegacao" : "Abrir navegacao"}
        >
          {open ? <X className="h-5 w-5" aria-hidden="true" /> : <Menu className="h-5 w-5" aria-hidden="true" />}
        </button>
      </div>

      <div className="mx-auto hidden max-w-7xl pt-4 lg:block">
        <div className="flex flex-wrap gap-2">
          {(data?.user ? resolvedLinks : guestLinks).map((link) => (
            <NavPill key={link.href} link={link} active={pathname === link.href} />
          ))}
        </div>
      </div>

      <AnimatePresence>
        {open ? (
          <motion.div
            id="app-menu"
            initial={{ opacity: 0, y: -10, scale: 0.98 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -8, scale: 0.98 }}
            transition={{ duration: 0.2, ease: "easeOut" }}
            className="mx-auto mt-4 max-w-7xl lg:hidden"
          >
            <div className="overflow-hidden rounded-[28px] border border-white/10 bg-slate-950/95 p-4 shadow-2xl shadow-black/35 backdrop-blur-xl">
              {data?.user ? (
                <div className="mb-4 rounded-[24px] border border-white/10 bg-white/5 p-4 text-sm text-slate-200">
                  <p className="font-semibold text-white">{data.user?.name || data.user?.email}</p>
                  <p className="mt-1 text-slate-300">Plano atual: {getAccountPlanLabel(data.user?.plan)}</p>
                  <p className="mt-2 text-xs text-slate-400">
                    {needsEmailVerification
                      ? "Seu email ainda precisa de confirmacao para liberar toda a experiencia."
                      : "Tudo pronto para voce continuar de onde parou."}
                  </p>
                </div>
              ) : null}

              <div className="grid gap-2 sm:grid-cols-2">
                {(data?.user ? resolvedLinks : guestLinks).map((link) => (
                  <NavPill key={link.href} link={link} active={pathname === link.href} mobile onClick={() => setOpen(false)} />
                ))}
              </div>

              <div className="mt-4 flex flex-col gap-2 sm:flex-row">
                {data?.user ? (
                  <button
                    type="button"
                    onClick={() => signOut({ callbackUrl: "/login" })}
                    className="interactive-button flex min-h-[48px] w-full items-center justify-center rounded-2xl border border-white/15 px-4 py-3 text-sm text-slate-100 transition-all duration-200 hover:bg-white/10"
                  >
                    Sair da conta
                  </button>
                ) : (
                  <>
                    <Link
                      href="/login"
                      className="interactive-button flex min-h-[48px] w-full items-center justify-center rounded-2xl border border-white/15 px-4 py-3 text-sm text-slate-100 transition-all duration-200 hover:bg-white/10"
                    >
                      Entrar
                    </Link>
                    <Link
                      href="/register"
                      className="interactive-button flex min-h-[48px] w-full items-center justify-center rounded-2xl bg-[linear-gradient(135deg,#06b6d4,#10b981)] px-4 py-3 text-sm font-semibold text-white shadow-lg shadow-cyan-500/25 transition-all duration-200 hover:-translate-y-0.5"
                    >
                      Criar conta
                    </Link>
                  </>
                )}
              </div>
            </div>
          </motion.div>
        ) : null}
      </AnimatePresence>
    </nav>
  )
}

function NavPill({
  link,
  active,
  mobile = false,
  onClick,
}: {
  link: NavLink
  active: boolean
  mobile?: boolean
  onClick?: () => void
}) {
  const Icon = link.icon

  return (
    <Link
      href={link.href}
      onClick={onClick}
      aria-current={active ? "page" : undefined}
      className={`interactive-button flex min-h-[44px] items-center gap-3 rounded-2xl border px-4 py-3 text-sm transition-all duration-200 ${
        mobile ? "w-full justify-start" : ""}
      } ${
        active
          ? "border-cyan-300/30 bg-cyan-500/10 text-cyan-100 shadow-lg shadow-cyan-950/15"
          : "border-white/10 bg-white/5 text-slate-200 hover:-translate-y-0.5 hover:border-white/20 hover:bg-white/10"
      }`}
    >
      <Icon className="h-4 w-4" aria-hidden="true" />
      <span>{link.label}</span>
    </Link>
  )
}
